-- Create "internal_policy_assets" table
CREATE TABLE "internal_policy_assets" ("internal_policy_id" character varying NOT NULL, "asset_id" character varying NOT NULL, PRIMARY KEY ("internal_policy_id", "asset_id"), CONSTRAINT "internal_policy_assets_asset_id" FOREIGN KEY ("asset_id") REFERENCES "assets" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "internal_policy_assets_internal_policy_id" FOREIGN KEY ("internal_policy_id") REFERENCES "internal_policies" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create "internal_policy_entities" table
CREATE TABLE "internal_policy_entities" ("internal_policy_id" character varying NOT NULL, "entity_id" character varying NOT NULL, PRIMARY KEY ("internal_policy_id", "entity_id"), CONSTRAINT "internal_policy_entities_entity_id" FOREIGN KEY ("entity_id") REFERENCES "entities" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "internal_policy_entities_internal_policy_id" FOREIGN KEY ("internal_policy_id") REFERENCES "internal_policies" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create "internal_policy_identity_holders" table
CREATE TABLE "internal_policy_identity_holders" ("internal_policy_id" character varying NOT NULL, "identity_holder_id" character varying NOT NULL, PRIMARY KEY ("internal_policy_id", "identity_holder_id"), CONSTRAINT "internal_policy_identity_holders_identity_holder_id" FOREIGN KEY ("identity_holder_id") REFERENCES "identity_holders" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "internal_policy_identity_holders_internal_policy_id" FOREIGN KEY ("internal_policy_id") REFERENCES "internal_policies" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create "review_internal_policies" table
CREATE TABLE "review_internal_policies" ("review_id" character varying NOT NULL, "internal_policy_id" character varying NOT NULL, PRIMARY KEY ("review_id", "internal_policy_id"), CONSTRAINT "review_internal_policies_internal_policy_id" FOREIGN KEY ("internal_policy_id") REFERENCES "internal_policies" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "review_internal_policies_review_id" FOREIGN KEY ("review_id") REFERENCES "reviews" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
